from .bus import EventBus


class LoggingBus(EventBus):
    """EventBus that logs all emitted events."""

    def __init__(self):
        super().__init__()
        self.log = []

    def emit(self, event):
        """Log event then delegate to parent."""
        self.log.append(event)
        super().emit(event)

