from .bus import EventBus


class FilteredBus(EventBus):
    """EventBus that filters events by predicate."""

    def __init__(self, predicate=None):
        super().__init__()
        self.predicate = predicate or (lambda event: True)

    def emit(self, event):
        """Only emit if predicate passes."""
        if self.predicate(event):
            super().emit(event)

