from .bus import EventBus


class AsyncBus(EventBus):
    """EventBus that queues events for deferred processing."""

    def __init__(self):
        super().__init__()
        self._queue = []

    def emit(self, event):
        """Queue event for later processing."""
        self._queue.append(event)

    def flush(self):
        """Process all queued events."""
        for event in self._queue:
            super().emit(event)
        self._queue.clear()

