from .bus import EventBus


class PriorityBus(EventBus):
    """EventBus that processes events by priority."""

    def __init__(self):
        super().__init__()
        self._pending = []

    def emit(self, event):
        """Queue event with priority."""
        priority = event.get("priority", 0)
        self._pending.append((priority, event))

    def flush(self):
        """Process events highest priority first."""
        self._pending.sort(key=lambda x: -x[0])
        for _, event in self._pending:
            super().emit(event)
        self._pending.clear()

