from .bus import EventBus


class Dispatcher:
    """Dispatches events across multiple buses."""

    def __init__(self):
        self._buses = []

    def add_bus(self, bus):
        """Add a bus to the dispatch group."""
        if not isinstance(bus, EventBus):
            raise TypeError(f"Expected EventBus, got {type(bus).__name__}")
        self._buses.append(bus)

    def broadcast(self, event):
        """Emit event to all buses."""
        for bus in self._buses:
            bus.emit(event)

    def bus_count(self):
        return len(self._buses)

