from .bus import EventBus


class BusRegistry:
    """Named registry of EventBus instances."""

    def __init__(self):
        self._buses = {}

    def register(self, name, bus):
        """Register a named bus."""
        if not isinstance(bus, EventBus):
            raise TypeError(f"Expected EventBus, got {type(bus).__name__}")
        self._buses[name] = bus

    def get(self, name):
        """Get a bus by name."""
        return self._buses.get(name)

    def emit_to(self, name, event):
        """Emit event to a specific named bus."""
        bus = self.get(name)
        if bus is None:
            raise KeyError(f"No bus named '{name}'")
        bus.emit(event)

    def list_names(self):
        return list(self._buses.keys())
